"use client";

import { useRef, useEffect } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { Heading, Text } from "@/components/ui/Typography";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/Card";
import { MessageCircle, Clock, HeartHandshake } from "lucide-react";

if (typeof window !== "undefined") {
    gsap.registerPlugin(ScrollTrigger);
}

const steps = [
    {
        title: "1. Salve o n├║mero",
        desc: "Adicione a Dra. Aline aos seus contatos. Sem downloads, logins ou senhas para lembrar na hora do desespero.",
        icon: MessageCircle,
    },
    {
        title: "2. Mande sua d├║vida",
        desc: "A qualquer momento. Envie foto do term├┤metro, ├íudio do choro, v├¡deo da respira├º├úo. Receba aten├º├úo focada.",
        icon: Clock,
    },
    {
        title: "3. Respire aliviada",
        desc: "Tenha a conduta m├®dica baseada em evid├¬ncias. Saiba se ├® caso de pronto-socorro, observa├º├úo ou medica├º├úo.",
        icon: HeartHandshake,
    },
];

export function HowItWorks() {
    const container = useRef<HTMLDivElement>(null);
    const cardsRef = useRef<(HTMLDivElement | null)[]>([]);

    useEffect(() => {
        const ctx = gsap.context(() => {

            cardsRef.current.forEach((card, idx) => {
                if (!card) return;

                gsap.fromTo(card,
                    { opacity: 0, y: 50 },
                    {
                        opacity: 1,
                        y: 0,
                        duration: 0.8,
                        ease: "power2.out",
                        scrollTrigger: {
                            trigger: card,
                            start: "top 85%",
                            toggleActions: "play none none reverse"
                        }
                    }
                );
            });

        }, container);

        return () => ctx.revert();
    }, []);

    return (
        <section ref={container} className="relative py-24 px-4 md:px-8 bg-night-base z-10">

            <div className="max-w-4xl mx-auto text-center mb-20 relative">
                {/* Subtle decorative aurora blob */}
                <div className="absolute -top-10 left-1/2 -translate-x-1/2 w-48 h-48 bg-accent-lavender/10 blur-[80px] rounded-full" />

                <Heading as="h2" className="mb-4 relative z-10">
                    Como funciona o <span className="text-accent-lavender italic font-cormorant font-normal">acompanhamento</span>?
                </Heading>
                <Text className="relative z-10">Uma linha direta de cuidado, pensada para n├úo adicionar fric├º├úo ├á sua rotina exausta.</Text>
            </div>

            <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-8 md:gap-12 relative">

                {/* Connection Line (Desktop only) */}
                <div className="hidden md:block absolute top-[28%] left-[15%] right-[15%] border-t-[2px] border-dashed border-accent-pearl/10 z-0"></div>

                {steps.map((step, idx) => (
                    <div
                        key={idx}
                        ref={(el) => { if (el) cardsRef.current[idx] = el; }}
                        className="relative z-10 group"
                    >
                        {/* Step Node indicator */}
                        <div className="w-16 h-16 mx-auto mb-6 rounded-full bg-night-dark border border-accent-pearl/20 flex items-center justify-center relative overflow-hidden transition-all duration-500 group-hover:bg-accent-lavender/20 group-hover:border-accent-lavender/40 group-hover:scale-110">
                            <step.icon className="w-6 h-6 text-accent-champagne" />
                            {/* Internal glow pulse */}
                            <div className="absolute inset-0 bg-accent-lavender/20 blur-md opacity-0 group-hover:opacity-100 transition-opacity" />
                        </div>

                        <Card glass className="h-full pt-8 text-center transition-transform duration-300 hover:border-accent-pearl/20 hover:bg-night-dark/40">
                            <CardHeader className="pb-2">
                                <CardTitle className="text-xl text-accent-lavender">{step.title}</CardTitle>
                            </CardHeader>
                            <CardContent>
                                <Text variant="body" className="text-sm md:text-base leading-relaxed">
                                    {step.desc}
                                </Text>
                            </CardContent>
                        </Card>
                    </div>
                ))}

            </div>

        </section>
    );
}

"use client";

import { useRef, useEffect } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { Heading, Text } from "@/components/ui/Typography";

if (typeof window !== "undefined") {
    gsap.registerPlugin(ScrollTrigger);
}

const doubts = [
    "Mamou pouco... ser├í que t├í desidratando?",
    "Choro n├úo para, ├® c├│lica ou dor de ouvido?",
    "A febre voltou depois de 3h, posso dar rem├®dio de novo?",
    "Google disse que pode ser grave...",
    "Ligo pro PS agora ou espero amanhecer?",
];

export function Scene0317() {
    const container = useRef<HTMLDivElement>(null);
    const lockscreen = useRef<HTMLDivElement>(null);
    const cardsContainer = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const ctx = gsap.context(() => {
            // Pin the section and animate cards orbiting/appearing
            if (!container.current || !lockscreen.current || !cardsContainer.current) return;

            const cards = gsap.utils.toArray<HTMLElement>(".doubt-card");

            const tl = gsap.timeline({
                scrollTrigger: {
                    trigger: container.current,
                    start: "top top",
                    end: "+=150%", // Short pin as requested
                    pin: true,
                    scrub: 1,
                },
            });

            // Initial state: cards hidden and scattered
            gsap.set(cards, {
                opacity: 0,
                scale: 0.8,
                filter: "blur(10px)",
            });

            // Animation sequence
            // 1. Lockscreen fades in slightly
            tl.to(lockscreen.current, { scale: 0.95, opacity: 0.8, duration: 1 })

                // 2. Cards fly in randomly but orbit the center
                .to(cards, {
                    opacity: 1,
                    scale: 1,
                    filter: "blur(0px)",
                    duration: 2,
                    stagger: 0.3,
                    ease: "power2.out",
                    // Randomly scatter them around the lockscreen
                    x: () => gsap.utils.random(-250, 250),
                    y: () => gsap.utils.random(-200, 200),
                    rotation: () => gsap.utils.random(-15, 15),
                }, "<0.5")

                // 3. Dissolve effect as the user leaves the pin
                .to([lockscreen.current, cardsContainer.current], {
                    opacity: 0,
                    y: -100,
                    duration: 1.5,
                    ease: "power1.inOut",
                }, "+=1");

        }, container);

        return () => ctx.revert();
    }, []);

    return (
        <section ref={container} className="relative h-screen w-full flex items-center justify-center overflow-hidden bg-night-base/50">

            {/* Background Overlay to dark the scene */}
            <div className="absolute inset-x-0 bottom-0 h-1/2 bg-gradient-to-t from-night-base to-transparent pointer-events-none z-0" />

            {/* Center Lockscreen */}
            <div
                ref={lockscreen}
                className="relative z-10 flex flex-col items-center justify-center p-8 rounded-3xl"
            >
                <div className="text-8xl md:text-9xl font-nunito font-light tracking-tighter text-accent-pearl/90 drop-shadow-2xl">
                    03:17
                </div>
                <Text variant="caption" className="mt-2 text-accent-pearl/50 uppercase tracking-widest">
                    Sexta-feira, Madrugada
                </Text>

                {/* Fake Lockscreen Notification */}
                <div className="mt-12 w-80 p-4 rounded-[20px] bg-night-dark/60 backdrop-blur-md border border-white/5 shadow-2xl">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-accent-coral/20 flex items-center justify-center">
                            <span className="text-xs text-accent-coral font-bold">A</span>
                        </div>
                        <div>
                            <div className="text-sm font-semibold text-accent-pearl">Aline Cuida</div>
                            <div className="text-xs text-accent-pearl/70 line-clamp-2">Voc├¬ tem uma nova mensagem de orienta├º├úo m├®dica.</div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Doubt Cards Container */}
            <div ref={cardsContainer} className="absolute inset-0 pointer-events-none z-20 flex items-center justify-center">
                {doubts.map((doubt, index) => (
                    <div
                        key={index}
                        className="doubt-card absolute p-4 w-60 bg-night-dark/80 backdrop-blur-xl border border-white/10 rounded-2xl shadow-[0_8px_32px_0_rgba(0,0,0,0.5)]"
                    >
                        <p className="text-sm font-nunito text-accent-champagne leading-relaxed">
                            "{doubt}"
                        </p>
                    </div>
                ))}
            </div>

        </section>
    );
}

"use client";

import { useState } from "react";
import { Heading, Text } from "@/components/ui/Typography";
import { Card } from "@/components/ui/Card";
import { MessageCircle, Send } from "lucide-react";

export function Simulator() {
    const [step, setStep] = useState<"idle" | "typing" | "answered">("idle");
    const [selectedCase, setSelectedCase] = useState("");

    const simulateResponse = (caseType: string) => {
        setSelectedCase(caseType);
        setStep("typing");
        setTimeout(() => {
            setStep("answered");
        }, 1500);
    };

    return (
        <section className="relative py-24 md:py-32 bg-night-dark z-10 px-4">

            <div className="max-w-4xl mx-auto text-center mb-16">
                <Heading as="h2" className="mb-4 text-accent-pearl">
                    Experimente o <span className="text-accent-coral font-cormorant italic font-normal">acolhimento.</span>
                </Heading>
                <Text className="text-accent-pearl/80">
                    Simula├º├úo interativa baseada em casos reais (sempre procure um m├®dico presencial em emerg├¬ncias).
                </Text>
            </div>

            <div className="max-w-2xl mx-auto">
                <Card className="bg-night-base border-white/10 shadow-2xl relative overflow-visible">

                    {/* Animated decorative sprout from Linha Viva */}
                    {step !== "idle" && (
                        <div className="absolute -top-6 -right-6 w-12 h-12 bg-accent-sage rounded-full flex items-center justify-center animate-[bounce_0.5s_ease-out] shadow-[0_0_20px_rgba(168,188,161,0.5)]">
                            <span className="text-night-base text-xl">­ƒî▒</span>
                        </div>
                    )}

                    <div className="flex flex-col space-y-4 mb-8">
                        <Text className="font-semibold text-accent-pearl mb-2">Qual ├® a sua d├║vida agora?</Text>

                        <button
                            onClick={() => simulateResponse("febre")}
                            disabled={step !== "idle"}
                            className="group text-left p-4 rounded-2xl border border-white/5 bg-white/5 hover:bg-white/10 transition-colors disabled:opacity-50"
                        >
                            <div className="flex items-center justify-between">
                                <span className="text-accent-pearl/90 group-hover:text-white transition-colors">"38.5 de febre e n├úo quer mamar"</span>
                                <Send className="w-4 h-4 text-accent-coral opacity-0 group-hover:opacity-100 transition-opacity" />
                            </div>
                        </button>

                        <button
                            onClick={() => simulateResponse("colica")}
                            disabled={step !== "idle"}
                            className="group text-left p-4 rounded-2xl border border-white/5 bg-white/5 hover:bg-white/10 transition-colors disabled:opacity-50"
                        >
                            <div className="flex items-center justify-between">
                                <span className="text-accent-pearl/90 group-hover:text-white transition-colors">"Choro inconsol├ível h├í 2 horas"</span>
                                <Send className="w-4 h-4 text-accent-coral opacity-0 group-hover:opacity-100 transition-opacity" />
                            </div>
                        </button>
                    </div>

                    {/* Conditional Response Box */}
                    <div className={`transition-all duration-500 overflow-hidden ${step === 'idle' ? 'h-0 opacity-0' : 'h-auto opacity-100 mt-8 pt-6 border-t border-white/10'}`}>
                        <div className="bg-[#DCF8C6]/10 text-accent-pearl p-4 md:p-6 rounded-2xl border border-accent-sage/30 flex gap-4 relative">

                            <div className="mt-1 flex-shrink-0">
                                <div className="w-8 h-8 rounded-full bg-accent-sage flex items-center justify-center">
                                    <span className="font-bold text-night-base text-xs">AC</span>
                                </div>
                            </div>

                            <div>
                                <p className="text-sm font-semibold text-accent-sage mb-1 mt-1">Dra. Aline Cuida</p>
                                {step === "typing" ? (
                                    <div className="flex gap-1 h-6 items-center">
                                        <span className="w-1.5 h-1.5 bg-accent-sage rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                        <span className="w-1.5 h-1.5 bg-accent-sage rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                        <span className="w-1.5 h-1.5 bg-accent-sage rounded-full animate-bounce"></span>
                                    </div>
                                ) : (
                                    <Text variant="body" className="text-accent-pearl/90 text-[15px] leading-relaxed">
                                        {selectedCase === "febre"
                                            ? "Calma, m├úe. Primeiro, vamos checar o estado geral dele. Ele est├í muito caidinho ou interage um pouco? O choro ├® forte?"
                                            : "O choro longo assusta, mas na maioria das vezes, nessa idade, ├® c├│lica. Vamos tentar algumas manobras de al├¡vio que vou te mandar no v├¡deo abaixo enquanto conversamos."}
                                    </Text>
                                )}
                            </div>
                        </div>

                        {step === "answered" && (
                            <div className="mt-8 text-center animate-in fade-in slide-in-from-bottom-4 duration-500">
                                <button className="flex items-center mx-auto text-sm text-accent-coral font-medium hover:text-accent-champagne transition-colors group">
                                    <MessageCircle className="w-4 h-4 mr-2 group-hover:scale-110 transition-transform" />
                                    Iniciar atendimento real
                                </button>
                            </div>
                        )}
                    </div>

                </Card>
            </div>
        </section>
    );
}

"use client";

import { useRef, useEffect } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { Heading, Text } from "@/components/ui/Typography";

if (typeof window !== "undefined") {
    gsap.registerPlugin(ScrollTrigger);
}

const testimonials = [
    { name: "Mariana Silva", quote: "No meio de uma crise de choro ├ás 4h da manh├ú, a resposta da Dra. Aline me deu o ch├úo que eu precisava. O menino dormiu em meia hora." },
    { name: "Fernanda Costa", quote: "Chega de Google. Eu vivia assustada com qualquer sintoma. Ter a palavra de uma pediatra especialista na hora foi um divisor de ├íguas." },
    { name: "Juliana Mendes", quote: "O acompanhamento continuado ├® lindo. Ela lembrou do ├║ltimo epis├│dio respirat├│rio dele sem eu precisar repetir a hist├│ria inteira." },
    { name: "Carla P.", quote: "Nunca achei que me sentiria t├úo acolhida pelo WhatsApp. Vale cada centavo do plano anual." },
];

export function Testimonials() {
    const container = useRef<HTMLDivElement>(null);
    const track = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const ctx = gsap.context(() => {

            if (!track.current || !container.current) return;

            const tl = gsap.timeline({
                scrollTrigger: {
                    trigger: container.current,
                    start: "top top",
                    end: () => `+=${track.current?.scrollWidth}`,
                    pin: true,
                    scrub: 1,
                }
            });

            tl.to(track.current, {
                x: () => -(track.current!.scrollWidth - window.innerWidth + 100),
                ease: "none"
            });

        }, container);

        return () => ctx.revert();
    }, []);

    return (
        <section ref={container} className="relative h-screen bg-night-base flex items-center overflow-hidden z-10 w-full">

            <div className="absolute top-20 left-4 md:left-12 z-20 pointer-events-none">
                <Heading as="h2" className="text-4xl md:text-6xl">
                    Quem j├í <br />
                    <span className="text-accent-coral italic font-cormorant font-normal">respirou aliviada</span>
                </Heading>
            </div>

            <div ref={track} className="flex gap-8 pl-4 md:pl-20 mt-40">
                {testimonials.map((t, i) => (
                    <div
                        key={i}
                        className="w-[300px] md:w-[450px] flex-shrink-0 bg-night-dark/60 border border-white/5 rounded-[2rem] p-8 md:p-12 shadow-xl backdrop-blur-sm relative group"
                    >
                        {/* Shimmer Effect */}
                        <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-white/5 to-transparent -translate-x-full group-hover:animate-[shimmer_2s_infinite] pointer-events-none" />

                        <svg className="w-10 h-10 text-accent-lavender/30 mb-6" fill="currentColor" viewBox="0 0 24 24"><path d="M14.017 21v-7.391c0-5.704 3.731-9.57 8.983-10.609l.995 2.151c-2.432.917-3.995 3.638-3.995 5.849h4v10h-9.983zm-14.017 0v-7.391c0-5.704 3.748-9.57 9-10.609l.996 2.151c-2.433.917-3.996 3.638-3.996 5.849h3.983v10h-9.983z" /></svg>

                        <Text variant="body" className="text-accent-pearl/90 italic font-cormorant text-xl md:text-2xl mb-8 leading-relaxed">
                            "{t.quote}"
                        </Text>

                        <Text variant="caption" className="font-bold text-accent-coral tracking-widest uppercase">
                            {t.name}
                        </Text>
                    </div>
                ))}
            </div>

            {/* Edge gradient to fade out left edge text */}
            <div className="absolute left-0 top-0 bottom-0 w-12 md:w-32 bg-gradient-to-r from-night-base to-transparent z-10 pointer-events-none" />

        </section>
    );
}
